# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
        Debug.Log("Player Health: " + health);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Player Currency: " + currency);
    }

    public bool PurchaseItem(int itemPrice)
    {
        if (currency >= itemPrice)
        {
            currency -= itemPrice;
            Debug.Log("Item Purchased! Remaining Currency: " + currency);
            return true;
        }
        Debug.Log("Not enough currency to purchase item.");
        return false;
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void BuyHealthPotion()
    {
        int potionPrice = 10;
        if (playerStats.PurchaseItem(potionPrice))
        {
            playerStats.health += 20; // Heal player by 20
            Debug.Log("Health Potion Used! Current Health: " + playerStats.health);
        }
    }

    public void BuyGold(int amount)
    {
        int goldPrice = amount * 5; // Example price calculation
        if (playerStats.PurchaseItem(goldPrice))
        {
            playerStats.AddCurrency(amount);
            Debug.Log("Gold Purchased! Current Currency: " + playerStats.currency);
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;

    void Start()
    {
        playerStats = gameObject.AddComponent<PlayerStats>();
        playerStats.AddCurrency(50); // Starting currency for testing
    }

    void Update()
    {
        // Example damage and purchase calls for testing
        if (Input.GetKeyDown(KeyCode.D)) // Press D to take damage
        {
            playerStats.TakeDamage(10);
        }

        if (Input.GetKeyDown(KeyCode.P)) // Press P to buy a health potion
        {
            Shop shop = gameObject.AddComponent<Shop>();
            shop.playerStats = playerStats;
            shop.BuyHealthPotion();
        }

        if (Input.GetKeyDown(KeyCode.G)) // Press G to buy gold
        {
            Shop shop = gameObject.AddComponent<Shop>();
            shop.playerStats = playerStats;
            shop.BuyGold(5); // Buy 5 gold
        }
    }
}